import ApiService, { ResponseType } from '@/api/api';
import { getTokenByBridge } from '@/utils';

export default {
  async getCode(obj: any): ResponseType<string> {
    const token = await getTokenByBridge();
    return ApiService.post('/parent/api/v1/operation/banner/reedm-code', {
      ...obj,
      token
    });
  }
};
